var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_PRACTICE","text":{"KOREA":"물론이죠. 출연하고 말고요!","JPN":"もちろんです。出演します！","ENG":"Of course. Of course I will be on!","TWN":"一定要的，我當然要演！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_PRACTICE","text":{"KOREA":"네, 감사합니다! 내일 뵙겠습니다!","JPN":"はい、ありがとうございます！　明日お伺いします！","ENG":"Yes, thank you! See you tomorrow!","TWN":"是，謝謝！明天見！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_PRACTICE","text":{"KOREA":"…음?","JPN":"……あれ？","ENG":"...Hmm?","TWN":"…嗯？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_PRACTICE","text":{"KOREA":"방금 뒤에서 무슨 소리가…?","JPN":"今、後ろから何か音が……？","ENG":"I think I heard something...?","TWN":"剛剛後面好像有什麼聲音…？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"잠시 실례하겠습니다, 아가씨.","JPN":"ちょっと失礼いたします、お嬢様。","ENG":"Excuse me for a moment, miss.","TWN":"抱歉囉，小姐。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK_02"},{"id":"L8_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_PRACTICE","text":{"KOREA":"네?","JPN":"えっ？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ACTOR_NPC_DRAMA_PRACTICE","text":{"KOREA":"꺄아악!!","JPN":"きゃああっ！！","ENG":"Kyaaak!!","TWN":"啊啊啊！！"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"이게 어떻게 된 거지?","JPN":"いったいどうなってるんだ？","ENG":"What’s going on?","TWN":"這是怎麼回事？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"파벨라를 연기할 배우가 한 명 밖에 안 나왔다고? 그게 말이 돼?","JPN":"ファヴェーラを演じる女優が1人しか来なかっただと？　そんなことあり得るか？","ENG":"There's only one actress to play Fabella? That makes no sense!","TWN":"只有一個演員來試鏡帕貝拉的角色？這怎麼可能？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"그것도 전원이 리허설 바로 전날에?!","JPN":"それも全員リハーサルの前日に！？","ENG":"And... they’re all not here on the day before the rehearsal?!","TWN":"而且還是在排演前一天？！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L18_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"그러게요.","JPN":"そうですよね。","ENG":"Tell me about it.","TWN":"就是說嘛～"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"이 정도면 자격을 떠나서 배우로서 기본이 안된 거 아닌가?","JPN":"これだと資格はともかく、女優として基本がなってないのではないですか？","ENG":"Regardless of the qualifications, the rest don’t even have the basics as an actor.","TWN":"這樣根本連當演員的資格都沒有嘛～"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"끄응…","JPN":"ぐぬぬ……","ENG":"Well...","TWN":"嗯…"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"뭐, 그래도 한 사람은 왔으니 최악은 면했군.","JPN":"まあ、それでも1人は来たし、最悪な事態は免れたな。","ENG":"At least one person is here, so the worst is behind us.","TWN":"起碼有來一個，還不到最慘的情況。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"그럼 잘 부탁드려요, 감독님.","JPN":"それじゃあ、よろしくお願いします、監督。","ENG":"I won't let you down, Mr. Director.","TWN":"那就請多多指教囉，導演。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"으흠, 정말로 하루만에 다른 후보들이 코빼기조차 비치지 않다니.","JPN":"ふむ、本当にたったの一日で他の候補がまったく現われなくなるとは。","ENG":"Mm-hmm, it took only a day for the other candidates to not show up.","TWN":"嗯哼，竟然真的一天之內就擺平其他競爭對手，"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"제법이구나, 시종.","JPN":"やるではないか、僕。","ENG":"You did a good job, servant.","TWN":"有兩下子喔，僕人。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"별 말씀을. 인간이라면 다들 하나씩 있는 약점을 이용해 처리했을 뿐이랍니다.","JPN":"とんでもありません。人間なら皆1つは持っている弱点を利用して処理しただけです。","ENG":"No need to say that. I just used the weakness that humans all have to take care of them.","TWN":"不敢不敢，我只是利用人類的弱點來解決他們而已。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"저기. 그런데 난 언제까지 여기서 이러고 가만히 서있어야 해?","JPN":"なあ、ところでアタシはいつまでここにじっと立ってないとダメなんだ？","ENG":"Excuse me? For how long am I supposed to stand here like this?","TWN":"我說，我要在這裡站到什麼時候？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"네 녀석을 혼자 두고 왔다간 집에 있는 소파를 다 뜯어먹을 것 같아서 말이다.","JPN":"貴様を1人にしていたら、家中のソファを全部噛みちぎられそうでな。","ENG":"I figured you would chew up the whole sofa if I left you alone.","TWN":"我怕你自己在家的話，等回到家之後可能所有的沙發都會報銷。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"주인님을 보필하는 것이 우리의 숙명이란다, 동생아.","JPN":"ご主人様を補佐するのが私たちの宿命だ、妹よ。","ENG":"It’s our destiny to support our Mistress, my little sister.","TWN":"妹妹，輔助主人是我們的使命。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L34_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"오늘 하루는 간만에 외출하신 주인님을 모시도록 하자꾸나.","JPN":"今日くらいは、久しぶりに外出なさったご主人様にお仕えしよう。","ENG":"Let’s do our best to serve our Mistress today.","TWN":"主人今天難得外出，我們要好好服侍主人！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"알겠어.","JPN":"わかった。","ENG":"Okay.","TWN":"好啦！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"끄응… 이빨 가려워.","JPN":"ううっ……牙がかゆい。","ENG":"Ugh... My teeth are itchy.","TWN":"噢…牙齒好癢。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"이 씬은 아주 중요한 장면이야.","JPN":"ここはとても重要なシーンだ。","ENG":"This is a very important scene.","TWN":"這個場景非常重要！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L39_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"프레데리카에게 짝사랑하던 남자를 빼앗긴 욕망의 화신 파벨라가 나무 뒤에서 분함에 치를 떠는 모습!","JPN":"片思いをしてた男をフレデリカに奪われた欲望の化身、ファヴェーラが木の後ろで悔しさから身震いている姿！","ENG":"Fabella, the incarnation of desire, is deprived of her unrequited love and trembles with anger behind a tree!","TWN":"慾望的化身 帕貝拉，知道暗戀的男生被弗蕾德莉卡搶走後，在樹後怒視著！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"파벨라가 어쩌다가 프레데리카와 대척점에 서게 됐는지를 보여주는 부분이지!","JPN":"ファヴェーラがどうしてフレデリカと正反対の立場になったのかを見せる場面だ！","ENG":"It’s a scene that shows why Fabella ended up as enemies with Frederica!","TWN":"這場戲就是在解釋，帕貝拉為何會和弗蕾德莉卡反目！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"걱정 마세요. 분노 연기라면 자신 있으니까.","JPN":"心配しないでください。怒る演技なら自信がありますから。","ENG":"Don't worry. I'm confident when it comes to acting angry.","TWN":"導演放心，憤怒的演技我很會。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_PRIDE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"감정 잡고…","JPN":"感情を込めて……","ENG":"Now, ready...","TWN":"情緒Hold住…"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"액션!","JPN":"アクション！","ENG":"Action!","TWN":"Action！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_SNAP"},{"id":"L46_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"큿! 저 여잔 뭐야?","JPN":"くっ！　あの女は何んだ？","ENG":"Argh! Who is she?","TWN":"哼！那個臭女人！"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_HATE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"대체 뭔데 내가 원하는 걸 자꾸 가로채 가는 거냐고!","JPN":"なんでアタシの欲しいものを全部奪っていくんだ！","ENG":"Why does she keep taking away what I want?!","TWN":"老是搶走我喜歡的東西！"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"복수해주겠어. 네가 사랑하는 것들을 전부 박살내서라도…!","JPN":"復讐してやる。あんたが愛するすべてを壊してでも……！","ENG":"I’m going to take revenge. I’m going to do whatever it takes...!","TWN":"我要報仇！我要毀掉你心愛的一切…！"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"컷! 컷!","JPN":"カット！　カット！","ENG":"Cut! Cut!","TWN":"Cut！Cut！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"나쁜 건 아닌데, 캐릭터를 좀 더 살려볼 순 없어?","JPN":"悪くはないけどさ、もっとキャラクターらしさを生かしてくれないか？","ENG":"It’s not that your acting’s bad, but I suppose you can do better to bring the character to life.","TWN":"是不到差的地步，但可以再進入角色一點嗎？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"…네?","JPN":"……えっ？","ENG":"...Huh?","TWN":"…什麼意思？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"지금은 너무 얌전한 아가씨 같잖아. 좀 더 적극적으로 화를 내봐.","JPN":"今のは大人しいお嬢さんみたいだったぞ。もっと積極的に怒りを表現してくれ。","ENG":"You seem like a tenderhearted young lady now. Try to be more aggressive.","TWN":"你現在感覺就是中規中矩的，我要你再激動一點！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"기왕이면 주변에 있는 사물을 이용해서 거친 모습을 보여주라고.","JPN":"どうせなら周りの物を利用して、荒ぶる姿を見せてくれよ。","ENG":"Use the things around you to show your rough side.","TWN":"也可以利用周圍的東西來表達你的憤怒。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"…아, 알았어요. 다시 해볼게요.","JPN":"……わ、わかりました。もう一度やってみます。","ENG":"…Oh, I see. Let me try again.","TWN":"…喔，好，我再試一次。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"크윽… 두고 봐!","JPN":"くっ……見てろよ！","ENG":"Ugh... Just you wait!","TWN":"哼…走著瞧！"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L9_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"반드시 되갚아주겠어!","JPN":"必ずやり返してやる！","ENG":"I’m going to take revenge!","TWN":"我一定會百倍奉還！"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"컷!","JPN":"カット！","ENG":"Cut!","TWN":"Cut！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"지금 뭐하는 거야?","JPN":"何やってんだ？","ENG":"What are you doing?","TWN":"你在幹什麼？"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"뭐하냐니… 손수건을 물어뜯으면서 분노를 표현했는데요?","JPN":"何って……ハンカチを噛んで怒りを表現したんですけど。","ENG":"Huh? I expressed my anger by biting on the handkerchief.","TWN":"什麼幹什麼…就咬手帕表達我的憤怒啊？"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"아니지. 그걸로는 부족해.","JPN":"違う。それじゃ足りないんだ。","ENG":"No. That’s not enough.","TWN":"不是這樣啦，光咬手帕還不夠！"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"파벨라는 둘째가라면 서러운 무력을 소유한 사관학교 전투 엘리트 출신이야.","JPN":"ファヴェーラは右に出るものがいない武力を持つ士官学校の戦闘エリート出身なんだよ。","ENG":"Fabella is a combat elite that comes from a military school.","TWN":"帕貝拉可是名門士官學校的戰鬥菁英，"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"겨우 손수건 한 장을 찢는 것보다 훨씬 폭력적이어야 한다고! 예를 들어…","JPN":"ただハンカチを噛むんじゃなくて、もっと暴力的じゃないと！　例えば……","ENG":"You have to be much more aggressive than simply biting on a handkerchief! For example...","TWN":"要比咬條手帕再更暴力一點！譬如…"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"그래, 바로 저 여자처럼 말이야!","JPN":"そうだ、あの女のように！","ENG":"Yes, just like that woman over there!","TWN":"有了，就像那個女的一樣！"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L21_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"저 여자…?","JPN":"あの女……？","ENG":"That woman...?","TWN":"那個女的…？"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"크르릉…!","JPN":"ガルル……！","ENG":"Grrrr...!","TWN":"啃啃啃…！"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"저게 뭐하는 건데요? 나무를 이빨로 물어뜯고 있잖아요?","JPN":"あれ……のことですか？　木に噛みついているように見えますけど？","ENG":"She’s chewing on the tree with her teeth. Is that what you want me to do?","TWN":"像她一樣？她在用牙齒啃樹木欸？"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"이해하겠어? 저런 야성미 넘치는 폭력성이야 말로 파벨라가 가진 역할의 핵심이라고.","JPN":"わかるか？　あんな風に野性感あふれる暴力性こそ、ファヴェーラの役の核心なんだよ。","ENG":"Get my point? That kind of raw violence is the core of Fabella’s character.","TWN":"這樣你懂了嗎？帕貝拉這個角色的重點，就是那種狂野火爆的作風！"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"아, 알겠어요. 하면 될 거 아녜요.","JPN":"わ、わかりましたよ。やればいいんでしょう？","ENG":"Fine, I got it. I’ll do it.","TWN":"喔，懂了，啃就啃。"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"헉, 헉… 이 정도면 됐죠?","JPN":"はあ、はあ……これでいいですか？","ENG":"*Huff* *Huff…* This should do, right?","TWN":"呼，呼…這樣可以了吧？"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"음.","JPN":"うーん。","ENG":"Hmm.","TWN":"嗯。"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"썩 마음에는 안 들지만 어쩔 수 없지. 시간상 다음 씬으로 넘어갑시다.","JPN":"別に気に入らないけど、仕方ないか。時間の問題もあるし、次のシーンに移りましょう。","ENG":"I’m not too pleased about it, but well, we’re running out of time. Time for the next scene.","TWN":"雖然不是很滿意，但也只能這樣。時間不多，換下一個場景吧。"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"어이없어. 운 좋게 시상식에서 노미네이트 몇 번 받은 걸로 대단한 것처럼 유세 떨기는.","JPN":"呆れた。運よく何回かノミネートされたくらいで偉そうに。","ENG":"This is ridiculous. He’s only been nominated a few times at the award ceremony and he’s like on his high horse.","TWN":"有夠無言的，不過就是被提名過幾次影展，得過幾次獎，就在那邊囂張什麼。"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"두고 봐. 내가 뜨기만 하면 너 같은 건 바로 묻어버릴 거니까.","JPN":"見てなさい。私が人気女優になったら、あなたなんてすぐ葬ってやるんだから。","ENG":"You’ll see. Your reputation will become nothing as soon as I get famous.","TWN":"走著瞧，等我爆紅之後一定要你好看！"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"STAFF_NPC_DRAMA_NULL","text":{"KOREA":"어, 어? 거기 피해요!","JPN":"あ、あれ？　そこ、危ない！","ENG":"Um, huh? Hey you, get away!","TWN":"嗯？喂！快閃開！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"응? …꺄악!","JPN":"えっ……？　きゃあっ！","ENG":"Huh? ...Eeek!","TWN":"嗯？…啊！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"뭐지…? 나 살았나?","JPN":"なに……？　私、助かっ……た？","ENG":"What happened...? Am I still alive?","TWN":"現在是怎樣…？我還活著嗎？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"응? 당신…?","JPN":"あれっ？　あなたって……？","ENG":"Huh? You...?","TWN":"嗯？你不是…？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"괜찮으신가요? 하마터면 쓰러지는 나무에 깔리실 뻔했네요.","JPN":"大丈夫ですか？　危うく木の下敷きになるところでしたね。","ENG":"Are you okay? You were almost crushed by the tree.","TWN":"您沒事吧？差點就被倒下來的樹給壓到呢！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"뭐, 뭐하는 거야 당신! 누가 나한테 손대도 된다고 했어? 얼른 내려놔!","JPN":"あ、あなた何してるの！　私に触れてもいいって言った覚えはないわよ！　早く下ろして！","ENG":"W-what do you think you’re doing?! Who told you that you were allowed to touch me? Put me down!","TWN":"你在幹嘛！誰准你碰我的？快放我下來！"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"이런. 실례했습니다.","JPN":"おっと。失礼。","ENG":"Oh dear. My apologies.","TWN":"哎呀，真是抱歉。"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"그것도 못 피해? 그렇게 굼떠서야 얼마 살지도 못하겠네.","JPN":"あんなのもよけられないのか？　そんなに鈍かったら長生きはできないぞ。","ENG":"You couldn’t even avoid that? Being that slow, you won’t be able to live long.","TWN":"區區一棵樹也閃不過？你這樣應該活不久吧？"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"뭐래? 야! 애초에 네가 나무를 물어뜯는 바람에 이렇게 된 거잖아!!","JPN":"はぁ？　ちょっと！　そもそもそっちが木をかじったからこんなことになったんでしょ！？","ENG":"What did you say? Hey! This all happened because you chewed on the tree!","TWN":"說什麼你！說到底還不是因為你亂啃樹的關係！！"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"그랬나? 썩은 나무라서 약했나 보지.","JPN":"そうか？　木が腐って脆くなってただけだろう。","ENG":"Well, maybe the tree was weak because it was rotten.","TWN":"是嗎？那棵樹本來就是顆朽木吧？"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"뭐, 뭐야 저거?","JPN":"な、何よ？","ENG":"What’s with her attitude?","TWN":"你說什麼？"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"사과도 없이 뭐가 저렇게 뻔뻔해?","JPN":"謝りもしないで、なんて図々しいの？","ENG":"She really has a nerve. She’s not even apologizing!","TWN":"你不道歉還敢頂嘴？"},"stage":{"bg":"CITY_CENTER1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"}]`);export{e as default};